using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public static class TestHelpers
{
    public static SchoolContext CreateInMemoryContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        var context = new SchoolContext(options);
        return context;
    }

    public static SchoolContext CreateSeededContext(string? dbName = null)
    {
        var context = CreateInMemoryContext(dbName);
        SeedData(context);
        return context;
    }

    public static void SeedData(SchoolContext context)
    {
        var instructor1 = new Instructor
        {
            ID = 1,
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = new DateTime(2010, 1, 1),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { InstructorID = 1, Location = "Room 101" }
        };

        var instructor2 = new Instructor
        {
            ID = 2,
            LastName = "Jones",
            FirstMidName = "Jane",
            HireDate = new DateTime(2015, 6, 15),
            CourseAssignments = new List<CourseAssignment>()
        };

        context.Instructors.AddRange(instructor1, instructor2);

        var dept1 = new Department
        {
            DepartmentID = 1,
            Name = "Computer Science",
            Budget = 100000m,
            StartDate = new DateTime(2000, 1, 1),
            InstructorID = 1
        };

        var dept2 = new Department
        {
            DepartmentID = 2,
            Name = "Mathematics",
            Budget = 80000m,
            StartDate = new DateTime(2005, 9, 1),
            InstructorID = 2
        };

        context.Departments.AddRange(dept1, dept2);

        var course1 = new Course
        {
            CourseID = 1001,
            Title = "Intro to CS",
            Credits = 3,
            DepartmentID = 1,
            Department = dept1,
            Enrollments = new List<Enrollment>(),
            CourseAssignments = new List<CourseAssignment>()
        };

        var course2 = new Course
        {
            CourseID = 2001,
            Title = "Calculus",
            Credits = 4,
            DepartmentID = 2,
            Department = dept2,
            Enrollments = new List<Enrollment>(),
            CourseAssignments = new List<CourseAssignment>()
        };

        context.Courses.AddRange(course1, course2);

        var ca1 = new CourseAssignment { CourseID = 1001, InstructorID = 1 };
        var ca2 = new CourseAssignment { CourseID = 2001, InstructorID = 2 };
        context.CourseAssignments.AddRange(ca1, ca2);
        instructor1.CourseAssignments.Add(ca1);
        instructor2.CourseAssignments.Add(ca2);

        var student1 = new Student
        {
            ID = 10,
            LastName = "Adams",
            FirstMidName = "Alice",
            EnrollmentDate = new DateTime(2020, 9, 1),
            Enrollments = new List<Enrollment>()
        };

        var student2 = new Student
        {
            ID = 11,
            LastName = "Baker",
            FirstMidName = "Bob",
            EnrollmentDate = new DateTime(2021, 1, 15),
            Enrollments = new List<Enrollment>()
        };

        var student3 = new Student
        {
            ID = 12,
            LastName = "Clark",
            FirstMidName = "Carol",
            EnrollmentDate = new DateTime(2019, 9, 1),
            Enrollments = new List<Enrollment>()
        };

        context.Students.AddRange(student1, student2, student3);

        var enrollment1 = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 1001,
            StudentID = 10,
            Grade = Grade.A,
            Course = course1,
            Student = student1
        };

        var enrollment2 = new Enrollment
        {
            EnrollmentID = 2,
            CourseID = 2001,
            StudentID = 11,
            Grade = Grade.B,
            Course = course2,
            Student = student2
        };

        context.Enrollments.AddRange(enrollment1, enrollment2);
        student1.Enrollments.Add(enrollment1);
        student2.Enrollments.Add(enrollment2);
        course1.Enrollments.Add(enrollment1);
        course2.Enrollments.Add(enrollment2);

        context.SaveChanges();
    }
}

