{"file_text": "using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        var items = Enumerable.Range(1, 25)
            .Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            })
            .AsQueryable();

        var result = PaginatedList<Student>.Create(items, 1, 10);

        Assert.Equal(10, result.Count);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
    }

    [Fact]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        var items = Enumerable.Range(1, 25)
            .Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i:D2}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            })
            .AsQueryable();

        var result = PaginatedList<Student>.Create(items, 2, 10);

        Assert.Equal(10, result.Count);
        Assert.Equal(2, result.PageIndex);
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var items = Enumerable.Range(1, 25)
            .Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            })
            .AsQueryable();

        var result = PaginatedList<Student>.Create(items, 3, 10);

        Assert.Equal(5, result.Count);
        Assert.Equal(3, result.PageIndex);
    }

    [Fact]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var items = Enumerable.Range(1, 20)
            .Select(i => new Student { ID = i, LastName = "S", FirstMidName = "F", EnrollmentDate = DateTime.Today })
            .AsQueryable();

        var result = PaginatedList<Student>.Create(items, 1, 10);

        Assert.False(result.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var items = Enumerable.Range(1, 20)
            .Select(i => new Student { ID = i, LastName = "S", FirstMidName = "F", EnrollmentDate = DateTime.Today })
            .AsQueryable();

        var result = PaginatedList<Student>.Create(items, 2, 10);

        Assert.True(result.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_FirstPageOfTwo_ReturnsTrue()
    {
        var items = Enumerable.Range(1, 20)
            .Select(i => new Student { ID = i, LastName = "S", FirstMidName = "F", EnrollmentDate = DateTime.Today })
            .AsQueryable();

        var result = PaginatedList<Student>.Create(items, 1, 10);

        Assert.True(result.HasNextPage);
    }

    [Fact]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var items = Enumerable.Range(1, 20)
            .Select(i => new Student { ID = i, LastName = "S", FirstMidName = "F", EnrollmentDate = DateTime.Today })
            .AsQueryable();

        var result = PaginatedList<Student>.Create(items, 2, 10);

        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void TotalPages_CalculatedCorrectly()
    {
        var items = Enumerable.Range(1, 15)
            .Select(i => new Student { ID = i, LastName = "S", FirstMidName = "F", EnrollmentDate = DateTime.Today })
            .AsQueryable();

        var result = PaginatedList<Student>.Create(items, 1, 10);

        Assert.Equal(2, result.TotalPages);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var items = Enumerable.Empty<Student>().AsQueryable();

        var result = PaginatedList<Student>.Create(items, 1, 10);

        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
    }
}
