        var dept = new Department { DepartmentID = 1, Name = "D", Budget = 100, StartDate = DateTime.Today };
        context.Departments.Add(dept);
        var course = new Course { CourseID = 200, Title = "C", Credits = 3, DepartmentID = 1 };
        context.Courses.Add(course);
        context.SaveChanges();

        var ca = new CourseAssignment { CourseID = 200, InstructorID = 1 };
        context.CourseAssignments.Add(ca);
        context.SaveChanges();

        var retrieved = context.CourseAssignments.Find(200, 1);
        Assert.NotNull(retrieved);
    }

    [Fact]
    public void Enrollment_RelationshipsWork()
    {
