{"file_text": "using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests
{
    [Fact]
    public void SendNotification_EnqueuesNotification()
    {
        using var service = new NotificationService();

        service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("John Doe", notification.Message);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesEntityId()
    {
        using var service = new NotificationService();

        service.SendNotification("Course", "101", EntityOperation.UPDATE);

        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("101", notification.Message);
    }

    [Fact]
    public void SendNotification_DefaultUserIsSystem()
    {
        using var service = new NotificationService();

        service.SendNotification("Department", "5", EntityOperation.DELETE);

        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        using var service = new NotificationService();

        // Drain any pre-existing notifications from static queue
        while (service.ReceiveNotification() != null) { }

        var result = service.ReceiveNotification();
        Assert.Null(result);
    }

    [Fact]
    public void SendNotification_MultipleMessages_FIFO()
    {
        using var service = new NotificationService();

        service.SendNotification("A", "1", "First", EntityOperation.CREATE);
        service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);

        var first = service.ReceiveNotification();
        var second = service.ReceiveNotification();
        Assert.NotNull(first);
        Assert.NotNull(second);
        Assert.Equal("A", first.EntityType);
        Assert.Equal("B", second.EntityType);
    }

    [Fact]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        using var service = new NotificationService();

        service.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);

        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("New Student 'Alice' has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        using var service = new NotificationService();

        service.SendNotification("Course", "101", "CS101", EntityOperation.UPDATE);

        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Course 'CS101' has been updated", notification.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        using var service = new NotificationService();

        service.SendNotification("Department", "5", "Physics", EntityOperation.DELETE);

        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Department 'Physics' has been deleted", notification.Message);
    }

    [Fact]
    public void SendNotification_NullDisplayName_UsesIdFormat()
    {
        using var service = new NotificationService();

        service.SendNotification("Student", "42", null, EntityOperation.CREATE);

        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("ID: 42", notification.Message);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToNow()
    {
        using var service = new NotificationService();
        var before = DateTime.Now.AddSeconds(-1);

        service.SendNotification("Test", "1", EntityOperation.CREATE);

        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.True(notification.CreatedAt >= before);
        Assert.True(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        using var service = new NotificationService();

        var exception = Record.Exception(() => service.MarkAsRead(999));
        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        var exception = Record.Exception(() => service.Dispose());
        Assert.Null(exception);
    }
}
