using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests
{
    private CoursesController CreateController(SchoolContext context)
    {
        var env = new Mock<IWebHostEnvironment>();
        env.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        env.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        var logger = new Mock<ILogger<CoursesController>>();
        var controller = new CoursesController(context, env.Object, logger.Object);
        controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        return controller;
    }

    [Fact]
    public void Index_ReturnsViewWithCourses()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Details_ValidId_ReturnsCourse()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Details(1001) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Intro to CS", course.Title);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithDepartmentSelectList()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Create_Post_ValidCourse_RedirectsToIndex()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);
        var course = new Course
        {
            CourseID = 3001,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        var result = controller.Create(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(3, context.Courses.Count());
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);
        controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 3001, Title = "", Credits = 3, DepartmentID = 1 };

        var result = controller.Create(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Post_InvalidFileExtension_AddsModelError()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);
        var course = new Course { CourseID = 3001, Title = "Test", Credits = 3, DepartmentID = 1 };
        var file = CreateMockFile("test.exe", 1024);

        var result = controller.Create(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_FileTooLarge_AddsModelError()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);
        var course = new Course { CourseID = 3001, Title = "Test", Credits = 3, DepartmentID = 1 };
        var file = CreateMockFile("test.jpg", 6 * 1024 * 1024);

        var result = controller.Create(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_ValidImage_SavesAndRedirects()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);
        var course = new Course { CourseID = 3001, Title = "Test Course", Credits = 3, DepartmentID = 1 };
        var file = CreateMockFile("test.png", 1024);

        var result = controller.Create(course, file) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        var saved = context.Courses.Find(3001);
        Assert.NotNull(saved);
        Assert.Contains("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsView()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Edit(1001) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Intro to CS", course.Title);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Edit(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Edit(9999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_ValidCourse_RedirectsToIndex()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);
        var course = new Course
        {
            CourseID = 1001,
            Title = "Updated CS",
            Credits = 4,
            DepartmentID = 1
        };

        var result = controller.Edit(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);
        controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1001, Title = "", Credits = 3, DepartmentID = 1 };

        var result = controller.Edit(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsView()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Delete(1001) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Intro to CS", course.Title);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void DeleteConfirmed_RemovesCourseAndRedirects()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.DeleteConfirmed(1001) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Single(context.Courses);
    }

    private static IFormFile CreateMockFile(string fileName, long length)
    {
        var fileMock = new Mock<IFormFile>();
        var content = new byte[Math.Min(length, 1024)];
        var ms = new MemoryStream(content);
        fileMock.Setup(f => f.FileName).Returns(fileName);
        fileMock.Setup(f => f.Length).Returns(length);
        fileMock.Setup(f => f.OpenReadStream()).Returns(ms);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => ms.CopyTo(s));
        return fileMock.Object;
    }
}

