using Microsoft.AspNetCore.Mvc.ViewFeatures;

namespace ContosoUniversity.Tests.Controllers;

public class DepartmentsControllerTests
{
    private DepartmentsController CreateController(SchoolContext context)
    {
        var controller = new DepartmentsController(context);
        controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        return controller;
    }

    [Fact]
    public void Index_ReturnsViewWithDepartments()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Details_ValidId_ReturnsDepartment()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Details(1) as ViewResult;

        Assert.NotNull(result);
        var dept = Assert.IsType<Department>(result.Model);
        Assert.Equal("Computer Science", dept.Name);
    }

