    public void Details_InvalidId_ReturnsNotFound()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Details(999) as NotFoundResult;

        Assert.NotNull(result);
    }

