    public void Create_Get_ReturnsView()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(controller.ViewBag.InstructorID);
    }

    [Fact]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);
        var dept = new Department
        {
            Name = "Physics",
            Budget = 90000m,
            StartDate = new DateTime(2023, 1, 1),
            InstructorID = 1
        };

        var result = controller.Create(dept) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(3, context.Departments.Count());
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);
        controller.ModelState.AddModelError("Name", "Required");
        var dept = new Department { Name = "" };

        var result = controller.Create(dept) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsView()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Edit(1) as ViewResult;

        Assert.NotNull(result);
        var dept = Assert.IsType<Department>(result.Model);
        Assert.Equal("Computer Science", dept.Name);
    }

