    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Edit(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Edit(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Updated CS",
            Budget = 110000m,
            StartDate = new DateTime(2000, 1, 1),
            InstructorID = 1
        };

        var result = controller.Edit(dept) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);
        controller.ModelState.AddModelError("Name", "Required");
        var dept = new Department { DepartmentID = 1, Name = "" };

        var result = controller.Edit(dept) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsView()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Delete(1) as ViewResult;

        Assert.NotNull(result);
        var dept = Assert.IsType<Department>(result.Model);
        Assert.Equal("Computer Science", dept.Name);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.Delete(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        using var context = TestHelpers.CreateSeededContext();
        using var controller = CreateController(context);

        var result = controller.DeleteConfirmed(1) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Single(context.Departments);
    }
}

