using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Data;

public class SchoolContextTests
{
    [Fact]
    public void CanAddAndRetrieveStudent()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var student = new Student
        {
            LastName = "TestStudent",
            FirstMidName = "First",
            EnrollmentDate = new DateTime(2023, 1, 1)
        };

        context.Students.Add(student);
        context.SaveChanges();

        var retrieved = context.Students.First();
        Assert.Equal("TestStudent", retrieved.LastName);
        Assert.Equal("First", retrieved.FirstMidName);
    }

    [Fact]
    public void CanAddAndRetrieveCourse()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var dept = new Department { DepartmentID = 1, Name = "Test", Budget = 1000, StartDate = DateTime.Today };
        context.Departments.Add(dept);
        var course = new Course { CourseID = 100, Title = "Test Course", Credits = 3, DepartmentID = 1 };

        context.Courses.Add(course);
        context.SaveChanges();

        var retrieved = context.Courses.First();
        Assert.Equal("Test Course", retrieved.Title);
        Assert.Equal(3, retrieved.Credits);
    }

    [Fact]
    public void CanAddAndRetrieveDepartment()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 50000m,
            StartDate = new DateTime(2020, 1, 1)
        };

        context.Departments.Add(dept);
        context.SaveChanges();

        var retrieved = context.Departments.First();
        Assert.Equal("Engineering", retrieved.Name);
        Assert.Equal(50000m, retrieved.Budget);
    }

    [Fact]
    public void CanAddAndRetrieveInstructor()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var instructor = new Instructor
        {
            LastName = "TestProf",
            FirstMidName = "Doctor",
            HireDate = new DateTime(2015, 8, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        context.Instructors.Add(instructor);
        context.SaveChanges();

        var retrieved = context.Instructors.First();
        Assert.Equal("TestProf", retrieved.LastName);
    }

    [Fact]
    public void CourseAssignment_CompositeKey_Works()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var instructor = new Instructor
        {
            ID = 1,
            LastName = "Prof",
            FirstMidName = "Test",
            HireDate = DateTime.Today,
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);
        var dept = new Department { DepartmentID = 1, Name = "D", Budget = 100, StartDate = DateTime.Today };
        context.Departments.Add(dept);
        var course = new Course { CourseID = 200, Title = "C", Credits = 3, DepartmentID = 1 };
        context.Courses.Add(course);
        context.SaveChanges();

        var ca = new CourseAssignment { CourseID = 200, InstructorID = 1 };
        context.CourseAssignments.Add(ca);
        context.SaveChanges();

        var retrieved = context.CourseAssignments.Find(200, 1);
        Assert.NotNull(retrieved);
    }

    [Fact]
    public void Enrollment_RelationshipsWork()
    {
        using var context = TestHelpers.CreateSeededContext();

        var enrollment = context.Enrollments.Include(e => e.Course).Include(e => e.Student).First();

        Assert.NotNull(enrollment.Course);
        Assert.NotNull(enrollment.Student);
    }

    [Fact]
    public void OfficeAssignment_OneToOne_Works()
    {
        using var context = TestHelpers.CreateSeededContext();

        var instructor = context.Instructors
            .Include(i => i.OfficeAssignment)
            .First(i => i.ID == 1);

        Assert.NotNull(instructor.OfficeAssignment);
        Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
    }

    [Fact]
    public void Students_WithEnrollments_CanBeQueried()
    {
        using var context = TestHelpers.CreateSeededContext();

        var student = context.Students
            .Include(s => s.Enrollments)
            .First(s => s.ID == 10);

        Assert.NotNull(student.Enrollments);
        Assert.Single(student.Enrollments);
    }

    [Fact]
    public void Department_WithAdministrator_CanBeQueried()
    {
        using var context = TestHelpers.CreateSeededContext();

        var dept = context.Departments
            .Include(d => d.Administrator)
            .First(d => d.DepartmentID == 1);

        Assert.NotNull(dept.Administrator);
        Assert.Equal("Smith", dept.Administrator.LastName);
    }
}

