using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

public class ModelsTests
{
    [Fact]
    public void Person_FullName_ReturnsLastNameCommaFirst()
    {
        var student = new Student { LastName = "Doe", FirstMidName = "John" };

        Assert.Equal("Doe, John", student.FullName);
    }

    [Fact]
    public void Student_InheritsFromPerson()
    {
        var student = new Student
        {
            ID = 1,
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = DateTime.Today
        };

        Assert.IsAssignableFrom<Person>(student);
        Assert.Equal(1, student.ID);
    }

    [Fact]
    public void Instructor_InheritsFromPerson()
    {
        var instructor = new Instructor
        {
            ID = 2,
            LastName = "Prof",
            FirstMidName = "Test",
            HireDate = DateTime.Today
        };

        Assert.IsAssignableFrom<Person>(instructor);
    }

    [Fact]
    public void Course_Properties_SetCorrectly()
    {
        var course = new Course
        {
            CourseID = 1001,
            Title = "Test Course",
            Credits = 4,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/img/test.png"
        };

        Assert.Equal(1001, course.CourseID);
        Assert.Equal("Test Course", course.Title);
        Assert.Equal(4, course.Credits);
        Assert.Equal(1, course.DepartmentID);
        Assert.Equal("/img/test.png", course.TeachingMaterialImagePath);
    }

    [Fact]
    public void Department_Properties_SetCorrectly()
    {
        var dept = new Department
        {
            DepartmentID = 5,
            Name = "Physics",
            Budget = 75000m,
            StartDate = new DateTime(2020, 1, 1),
            InstructorID = 3
        };

        Assert.Equal(5, dept.DepartmentID);
        Assert.Equal("Physics", dept.Name);
        Assert.Equal(75000m, dept.Budget);
        Assert.Equal(3, dept.InstructorID);
    }

    [Fact]
    public void Enrollment_GradeValues()
    {
        Assert.Equal(0, (int)Grade.A);
        Assert.Equal(1, (int)Grade.B);
        Assert.Equal(2, (int)Grade.C);
        Assert.Equal(3, (int)Grade.D);
        Assert.Equal(4, (int)Grade.F);
    }

    [Fact]
    public void Enrollment_NullableGrade_CanBeNull()
    {
        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 100,
            StudentID = 10,
            Grade = null
        };

        Assert.Null(enrollment.Grade);
    }

    [Fact]
    public void EntityOperation_Values()
    {
        Assert.Equal(0, (int)EntityOperation.CREATE);
        Assert.Equal(1, (int)EntityOperation.UPDATE);
        Assert.Equal(2, (int)EntityOperation.DELETE);
    }

    [Fact]
    public void Notification_Properties_SetCorrectly()
    {
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "Test message",
            CreatedAt = DateTime.Now,
            CreatedBy = "Admin",
            IsRead = false,
            ReadAt = null
        };

        Assert.Equal(1, notification.Id);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("42", notification.EntityId);
        Assert.False(notification.IsRead);
        Assert.Null(notification.ReadAt);
    }

    [Fact]
    public void OfficeAssignment_Properties()
    {
        var oa = new OfficeAssignment
        {
            InstructorID = 1,
            Location = "Room 200"
        };

        Assert.Equal(1, oa.InstructorID);
        Assert.Equal("Room 200", oa.Location);
    }

    [Fact]
    public void CourseAssignment_Properties()
    {
        var ca = new CourseAssignment
        {
            InstructorID = 1,
            CourseID = 100
        };

        Assert.Equal(1, ca.InstructorID);
        Assert.Equal(100, ca.CourseID);
    }
}

