public void Index_WithCourseId_ReturnsViewResult()
{
    // This test verifies the controller handles courseID parameter.
    // The InMemory provider's Include behavior can duplicate navigation entries,
    // so we test with a minimal seed that avoids duplicates.
    var dbName = Guid.NewGuid().ToString();
    using var context = TestHelpers.CreateInMemoryContext(dbName);
    var instructor = new Instructor
    {
        ID = 1,
        LastName = "Smith",
        FirstMidName = "John",
        HireDate = new DateTime(2010, 1, 1),
        CourseAssignments = new List<CourseAssignment>()
    };
    context.Instructors.Add(instructor);
    var dept = new Department { DepartmentID = 1, Name = "CS", Budget = 1000, StartDate = DateTime.Today };
    context.Departments.Add(dept);
    var course = new Course
    {
        CourseID = 1001,
        Title = "Test",
        Credits = 3,
        DepartmentID = 1,
        Department = dept,
        Enrollments = new List<Enrollment>(),
        CourseAssignments = new List<CourseAssignment>()
    };
    context.Courses.Add(course);
    var ca = new CourseAssignment { CourseID = 1001, InstructorID = 1 };
    context.CourseAssignments.Add(ca);
    instructor.CourseAssignments.Add(ca);
    course.CourseAssignments.Add(ca);
    context.SaveChanges();

    using var controller = CreateController(context);
    var result = controller.Index(1, 1001) as ViewResult;

    Assert.NotNull(result);
    var model = Assert.IsType<InstructorIndexData>(result.Model);
    Assert.NotNull(model.Enrollments);
}

